import test from "node:test";
import assert from "node:assert/strict";

import { calculateInvoiceTotal } from "../src/invoice.js";

test("calculates a happy path invoice total", () => {
  assert.equal(
    calculateInvoiceTotal([{ price: 10, quantity: 2 }], { taxRate: 0.1 }),
    22
  );
});

test("applies a basic fixed discount on the happy path", () => {
  assert.equal(
    calculateInvoiceTotal([{ price: 20, quantity: 1 }], { discount: 5, taxRate: 0 }),
    15
  );
});

test("returns shipping only for empty items with zero discount", () => {
  assert.equal(
    calculateInvoiceTotal([], { discount: 0, taxRate: 0.1, shippingFee: 3.5 }),
    3.5
  );
});

test("applies a percent discount before tax", () => {
  assert.equal(
    calculateInvoiceTotal(
      [{ price: 50, quantity: 2 }],
      { discount: 0.25, discountType: "percent", taxRate: 0.1 }
    ),
    82.5
  );
});

test("applies an explicit fixed discount before tax", () => {
  assert.equal(
    calculateInvoiceTotal(
      [{ price: 30, quantity: 2 }],
      { discount: 10, discountType: "fixed", taxRate: 0.05 }
    ),
    52.5
  );
});

test("does not add tax when taxable=false", () => {
  assert.equal(
    calculateInvoiceTotal(
      [{ price: 12, quantity: 3 }],
      { taxable: false, taxRate: 0.5 }
    ),
    36
  );
});

test("adds shippingFee after discount and tax", () => {
  assert.equal(
    calculateInvoiceTotal(
      [{ price: 15, quantity: 2 }],
      { discount: 5, taxRate: 0.1, shippingFee: 4.25 }
    ),
    31.75
  );
});

test("throws for an invalid price", () => {
  assert.throws(
    () => calculateInvoiceTotal([{ price: -1, quantity: 1 }]),
    /item price must be a non-negative number/
  );
});

test("throws for an invalid quantity", () => {
  assert.throws(
    () => calculateInvoiceTotal([{ price: 1, quantity: 1.5 }]),
    /item quantity must be a non-negative integer/
  );
});

export function calculateInvoiceTotal(items, options = {}) {
  if (!Array.isArray(items)) {
    throw new TypeError("items must be an array");
  }

  const {
    discount = 0,
    discountType = "fixed",
    taxable = true,
    taxRate = 0.08,
    shippingFee = 0
  } = options;

  if (!Number.isFinite(discount) || discount < 0) {
    throw new RangeError("discount must be a non-negative number");
  }
  if (!Number.isFinite(taxRate) || taxRate < 0) {
    throw new RangeError("taxRate must be a non-negative number");
  }
  if (!Number.isFinite(shippingFee) || shippingFee < 0) {
    throw new RangeError("shippingFee must be a non-negative number");
  }

  const subtotal = items.reduce((sum, item) => {
    const price = Number(item?.price);
    const quantity = Number(item?.quantity);
    if (!Number.isFinite(price) || price < 0) {
      throw new RangeError("item price must be a non-negative number");
    }
    if (!Number.isInteger(quantity) || quantity < 0) {
      throw new RangeError("item quantity must be a non-negative integer");
    }
    return sum + price * quantity;
  }, 0);

  const discountAmount = discountType === "percent" ? subtotal * discount : discount;
  const discountedSubtotal = Math.max(0, subtotal - discountAmount);
  const tax = taxable ? discountedSubtotal * taxRate : 0;
  return roundCurrency(discountedSubtotal + tax + shippingFee);
}

function roundCurrency(value) {
  return Math.round(value * 100) / 100;
}

import { readFileSync } from "node:fs";

const testSource = readFileSync(new URL("../test/invoice.test.js", import.meta.url), "utf8").toLowerCase();

const requiredCoverage = [
  ["empty items", /\bempty items?\b|no items|items\s*=\s*\[\]/],
  ["zero discount", /\bzero discount\b|discount:\s*0/],
  ["percent discount", /\bpercent(?:age)? discount\b|discounttype:\s*["']percent["']/],
  ["fixed discount", /\bfixed discount\b|discounttype:\s*["']fixed["']/],
  ["taxable=false", /taxable\s*:\s*false|taxable=false|non-?taxable/],
  ["shippingFee", /shippingfee|shipping fee/],
  ["invalid price", /invalid price|negative price|price.*throw|price.*rangeerror/],
  ["invalid quantity", /invalid quantity|negative quantity|quantity.*throw|quantity.*rangeerror/]
];

const missing = requiredCoverage
  .filter(([, pattern]) => !pattern.test(testSource))
  .map(([name]) => name);

if (missing.length > 0) {
  console.error(`Missing required invoice coverage cases: ${missing.join(", ")}`);
  process.exit(1);
}

console.log("Invoice coverage contract satisfied.");

